using Contoso.Orders;

namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private readonly OrderService _service;

    public OrderServiceTests()
    {
        _service = new OrderService();
    }

    private static List<OrderItem> CreateItems(params (string name, decimal price, int qty)[] items) =>
        items.Select(i => new OrderItem { ProductName = i.name, Price = i.price, Quantity = i.qty }).ToList();

    #region CreateOrder

    [TestMethod]
    public void CreateOrder_WithValidItems_ReturnsOrderWithCorrectTotal()
    {
        // Arrange
        var items = CreateItems(("Widget", 10.00m, 2), ("Gadget", 25.00m, 1));

        // Act
        var order = _service.CreateOrder("cust-1", items);

        // Assert
        Assert.IsNotNull(order);
        Assert.AreEqual("cust-1", order.CustomerId);
        Assert.AreEqual(45.00m, order.Total);
        Assert.HasCount(2, order.Items);
    }

    [TestMethod]
    public void CreateOrder_WithValidItems_AssignsUniqueId()
    {
        // Arrange
        var items = CreateItems(("Widget", 5.00m, 1));

        // Act
        var order = _service.CreateOrder("cust-1", items);

        // Assert
        Assert.IsNotNull(order.Id);
        Assert.IsNotEmpty(order.Id);
    }

    [TestMethod]
    public void CreateOrder_WithValidItems_SetsCreatedAtToUtcNow()
    {
        // Arrange
        var items = CreateItems(("Widget", 5.00m, 1));
        var before = DateTime.UtcNow;

        // Act
        var order = _service.CreateOrder("cust-1", items);

        // Assert
        var after = DateTime.UtcNow;
        Assert.IsTrue(order.CreatedAt >= before && order.CreatedAt <= after);
    }

    [TestMethod]
    public void CreateOrder_MultipleCalls_AssignsDifferentIds()
    {
        // Arrange
        var items = CreateItems(("Widget", 5.00m, 1));

        // Act
        var order1 = _service.CreateOrder("cust-1", items);
        var order2 = _service.CreateOrder("cust-1", items);

        // Assert
        Assert.AreNotEqual(order1.Id, order2.Id);
    }

    [TestMethod]
    public void CreateOrder_NullCustomerId_ThrowsArgumentNullException()
    {
        // Arrange
        var items = CreateItems(("Widget", 5.00m, 1));

        // Act & Assert
        var ex = Assert.ThrowsExactly<ArgumentNullException>(() => _service.CreateOrder(null!, items));
        Assert.AreEqual("customerId", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_NullItems_ThrowsArgumentNullException()
    {
        var ex = Assert.ThrowsExactly<ArgumentNullException>(() => _service.CreateOrder("cust-1", null!));
        Assert.AreEqual("items", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_EmptyItems_ThrowsInvalidOperationException()
    {
        var ex = Assert.ThrowsExactly<InvalidOperationException>(
            () => _service.CreateOrder("cust-1", []));
        Assert.Contains("no items", ex.Message, StringComparison.OrdinalIgnoreCase);
    }

    [TestMethod]
    [DataRow(1, 10.00, 10.00, DisplayName = "Single item")]
    [DataRow(3, 7.50, 22.50, DisplayName = "Multiple quantity")]
    public void CreateOrder_SingleItem_CalculatesCorrectTotal(int qty, double price, double expectedTotal)
    {
        // Arrange
        var items = CreateItems(("Item", (decimal)price, qty));

        // Act
        var order = _service.CreateOrder("cust-1", items);

        // Assert
        Assert.AreEqual((decimal)expectedTotal, order.Total);
    }

    #endregion

    #region GetOrder

    [TestMethod]
    public void GetOrder_ExistingOrder_ReturnsOrder()
    {
        // Arrange
        var items = CreateItems(("Widget", 5.00m, 1));
        var created = _service.CreateOrder("cust-1", items);

        // Act
        var retrieved = _service.GetOrder(created.Id);

        // Assert
        Assert.IsNotNull(retrieved);
        Assert.AreSame(created, retrieved);
    }

    [TestMethod]
    public void GetOrder_NonExistentId_ReturnsNull()
    {
        var result = _service.GetOrder("non-existent-id");

        Assert.IsNull(result);
    }

    #endregion

    #region GetOrdersByCustomer

    [TestMethod]
    public void GetOrdersByCustomer_MultipleOrders_ReturnsAllForCustomer()
    {
        // Arrange
        var items = CreateItems(("Widget", 5.00m, 1));
        _service.CreateOrder("cust-1", items);
        _service.CreateOrder("cust-1", items);
        _service.CreateOrder("cust-2", items);

        // Act
        var orders = _service.GetOrdersByCustomer("cust-1");

        // Assert
        Assert.HasCount(2, orders);
    }

    [TestMethod]
    public void GetOrdersByCustomer_NoOrders_ReturnsEmptyList()
    {
        var orders = _service.GetOrdersByCustomer("unknown");

        Assert.IsEmpty(orders);
    }

    #endregion
}

using Contoso.Pricing;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private readonly PriceCalculator _calculator;

    public PriceCalculatorTests()
    {
        _calculator = new PriceCalculator();
    }

    #region CalculateTotal

    [TestMethod]
    [DataRow(10.00, 2, 0.10, 22.00, DisplayName = "10% tax")]
    [DataRow(10.00, 1, 0.00, 10.00, DisplayName = "No tax")]
    [DataRow(5.00, 3, 0.20, 18.00, DisplayName = "20% tax")]
    public void CalculateTotal_ValidInputs_ReturnsExpectedTotal(
        double unitPrice, int quantity, double taxRate, double expected)
    {
        var result = _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expected, result);
    }

    [TestMethod]
    public void CalculateTotal_NegativeQuantity_ThrowsArgumentOutOfRangeException()
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(10m, -1, 0.1m));
        Assert.AreEqual("quantity", ex.ParamName);
    }

    [TestMethod]
    public void CalculateTotal_NegativeUnitPrice_ThrowsArgumentOutOfRangeException()
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(-5m, 1, 0.1m));
        Assert.AreEqual("unitPrice", ex.ParamName);
    }

    [TestMethod]
    [DataRow(-0.01, DisplayName = "Negative tax rate")]
    [DataRow(1.01, DisplayName = "Tax rate above 1")]
    public void CalculateTotal_InvalidTaxRate_ThrowsArgumentOutOfRangeException(double taxRate)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(10m, 1, (decimal)taxRate));
        Assert.AreEqual("taxRate", ex.ParamName);
    }

    #endregion

    #region ApplyDiscount

    [TestMethod]
    [DataRow(100.00, 10.0, 90.00, DisplayName = "10% discount")]
    [DataRow(200.00, 50.0, 100.00, DisplayName = "50% discount")]
    [DataRow(100.00, 0.0, 100.00, DisplayName = "No discount")]
    [DataRow(100.00, 100.0, 0.00, DisplayName = "100% discount")]
    public void ApplyDiscount_ValidInputs_ReturnsExpectedPrice(
        double price, double discount, double expected)
    {
        var result = _calculator.ApplyDiscount((decimal)price, (decimal)discount);

        Assert.AreEqual((decimal)expected, result);
    }

    [TestMethod]
    [DataRow(-1.0, DisplayName = "Negative discount")]
    [DataRow(101.0, DisplayName = "Discount over 100%")]
    public void ApplyDiscount_InvalidPercent_ThrowsArgumentOutOfRangeException(double discount)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(100m, (decimal)discount));
    }

    #endregion

    #region FormatPrice

    [TestMethod]
    public void FormatPrice_DefaultCurrency_ReturnsDollarFormat()
    {
        var result = _calculator.FormatPrice(19.99m);

        Assert.AreEqual("$19.99", result);
        Assert.StartsWith("$", result);
    }

    [TestMethod]
    public void FormatPrice_CustomCurrency_UsesCurrencySymbol()
    {
        var result = _calculator.FormatPrice(19.99m, "€");

        Assert.AreEqual("€19.99", result);
        Assert.StartsWith("€", result);
    }

    [TestMethod]
    public void FormatPrice_WholeNumber_ShowsTwoDecimalPlaces()
    {
        var result = _calculator.FormatPrice(42m);

        Assert.EndsWith(".00", result);
    }

    #endregion
}

